Object.assign = null
import Starling from '../../src/index'
import { LocalStorage } from 'node-localstorage'
import { EN_TXT, EN_TXT_NEW } from '../data/remote-demo-en'

const request = jest.fn()

// 这里会生成本地文件
const storeInstance = new LocalStorage('./starling', 5 * 1024 * 1024)
const options = {
  timeout: 5000,
  apiKey: 'b112ff70cd5411e99543214b5ec42534',
  locale: 'en',
  zoneHost: 'https://starling.snssdk.com',
  namespace: 'test',
  store: {
    get(key) {
      const val = storeInstance.getItem(key)
      return JSON.parse(val)
    },
    set(key, value) {
      return storeInstance.setItem(key, JSON.stringify(value))
    },
    del(key) {
      return storeInstance.delete(key)
    }
  },
  tracker: () => {},
  request
}

class TestPlugin {
  type = 'afterLoad'
  constructor() {}

  async process(textMap, clientOps) {
    return {
      ...textMap,
      testplugin: 'test'
    }
  }
}

describe('集成测试 - Starling Client Core', () => {
  beforeEach(() => {
    storeInstance.clear()
  })
  afterEach(() => {
    storeInstance.clear()
  })

  test('初始化 - 失败', async () => {
    expect(() => {
      Object.assign(null)
      new Starling(null)
    }).toThrow()
  })

  test('load - 成功', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const starling = new Starling(options)
    // when
    const texts = await starling.load()
    // then
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 成功 - format: splitted', async () => {
    // given
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const starling = new Starling({ ...options, format: 'splitted' })
    // when
    const texts = await starling.load()
    // then
    expect(texts).toEqual({
      test: {
        texts: EN_TXT,
        version: '1',
        lang: 'en'
      }
    })
  })

  test('load - 成功 - lazyUpdate: true，本地无缓存返回远程数据', async () => {
    // given
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const starling1 = new Starling({ ...options, lazyUpdate: true })
    // when
    const texts = await starling1.load()
    // then
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 成功 - lazyUpdate: true，返回最新版本的本地缓存', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '2', Lang: 'en', Data: EN_TXT_NEW, Updated: true }
      }
    })
    const starling1 = new Starling(options)
    // when
    await starling1.load()
    starling1.setConfig({ lazyUpdate: true })
    await starling1.load()
    const texts = await starling1.waitForRefresh()
    // then
    expect(texts).toEqual(EN_TXT_NEW)
  })

  test('load - 成功 - 返回初始化参数中期待的语种', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'zh', Data: EN_TXT, Updated: true }
      }
    })
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '2', Lang: 'en', Data: EN_TXT_NEW, Updated: true }
      }
    })
    const starling1 = new Starling({ ...options })
    // when
    await starling1.load()
    const texts = await starling1.load()
    // then
    const URL_LOAD_TEXT = `${options.zoneHost}/check_and_get_text/${options.apiKey}/normal/${options.namespace}?lang=en,zh`
    expect(request).lastCalledWith(URL_LOAD_TEXT, { timeout: 5000 })
    expect(texts).toEqual(EN_TXT_NEW)
  })

  test('load - 成功 - version: 0.0.1', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const starling = new Starling({ ...options, lazyUpdate: true, version: '0.0.1' })
    const texts = await starling.load()
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 成功 - version: [0.0.1]', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const starling = new Starling({ ...options, version: ['0.0.1'] })
    const texts = await starling.load()
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 成功 - version: { test: 0.0.1}', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const starling = new Starling({ ...options, version: { test: '0.0.1' } })
    const texts = await starling.load()
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 成功 - 缓存 使用localforge情况下， text会是promise', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        // 模拟使用localforge情况下， text会是promise
        message: { Version: '1', Lang: 'en', Data: { ...EN_TXT, then: 'test' }, Updated: true }
      }
    })

    const storeInstanceTest = new LocalStorage('./starling', 5 * 1024 * 1024)
    storeInstanceTest.setItem(
      `text.${options.apiKey}.${options.namespace}.${options.locale}`,
      JSON.stringify({ ...EN_TXT, then: 'test' })
    )

    const starling = new Starling({
      ...options,
      store: {
        get(key) {
          const val = storeInstance.getItem(key)
          return JSON.parse(val)
        },
        set(key, value) {
          return storeInstance.setItem(key, JSON.stringify(value))
        },
        del(key) {
          return storeInstance.delete(key)
        }
      }
    })
    const texts = await starling.load().catch(e => {
      return e.response.data
    })
    expect(texts).toEqual({ ...EN_TXT, then: 'test' })
  })

  test('load - 成功 - 缓存 text 是空对象', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        // 模拟使用localforge情况下， text会是promise
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })

    const storeInstanceTest = new LocalStorage('./starling', 5 * 1024 * 1024)
    storeInstanceTest.setItem(
      `text.${options.apiKey}.${options.namespace}.${options.locale}`,
      JSON.stringify({})
    )

    const starling = new Starling({
      ...options
    })
    const texts = await starling.load().catch(e => {
      return e.response.data
    })
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 成功 - store的set抛出异常取', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })

    const storeInstanceTest = new LocalStorage('./starling', 5 * 1024 * 1024)
    storeInstanceTest.setItem(
      `text.${options.apiKey}.${options.namespace}.${options.locale}`,
      JSON.stringify(EN_TXT)
    )

    const starling = new Starling({
      ...options,
      store: {
        get(key) {
          const val = storeInstance.getItem(key)
          return JSON.parse(val)
        },
        set: () => {
          throw new Error('set error')
        },
        del(key) {
          return storeInstance.delete(key)
        }
      }
    })
    const texts = await starling.load().catch(e => {
      return e.response.data
    })
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 成功 - store的get抛出异常取', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })

    storeInstance.setItem(
      `text.${options.apiKey}.${options.namespace}.${options.locale}`,
      JSON.stringify(EN_TXT)
    )
    const starling = new Starling({
      ...options,
      store: {
        get(key) {
          throw new Error('set error')
        },
        set: (key, value) => {
          return storeInstance.setItem(key, JSON.stringify(value))
        },
        del(key) {
          return storeInstance.delete(key)
        }
      }
    })
    const texts = await starling.load().catch(e => {
      return e.response.data
    })
    expect(texts).toEqual(EN_TXT)
  })

  test('tracker - 抛出异常也不影响正常运转', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const starling = new Starling({
      ...options,
      tracker: () => {
        throw new Error('error')
      }
    })
    const texts = await starling.load()
    expect(texts).toEqual(EN_TXT)
  })

  test('load - 失败 - 请求异常', async () => {
    // given
    request.mockRejectedValue('error')
    const starling = new Starling(options)
    starling.load(
      () => {},
      err => {
        expect(err).toEqual('error')
      }
    )
  })

  test('load - 成功 - 请求异常使用本地缓存', async () => {
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    // given
    request.mockRejectedValueOnce({})
    const starling = new Starling(options)
    await starling.load()
    starling.load().catch(err => {
      expect(err.response.data).toEqual({})
    })
  })

  test('load - 成功 - 请求异常 本地缓存不为对象', async () => {
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })
    const storeInstanceTest = new LocalStorage('./starling', 5 * 1024 * 1024)
    storeInstanceTest.setItem(
      `text.${options.apiKey}.${options.namespace}.${options.locale}`,
      '222'
    )
    request.mockRejectedValueOnce({})
    const starling = new Starling(options)
    await starling.load()
    starling.load().catch(err => {
      expect(err.response.data).toEqual({})
    })
  })

  test('load - 成功 - cache true', async () => {
    // given
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '', Lang: '', Data: null, Updated: false }
      }
    })
    const starling = new Starling({
      ...options,
      store: {
        get(key) {
          return {
            cache: 'false'
          }
        },
        set(key, value) {
          return storeInstance.setItem(key, JSON.stringify(value))
        },
        del(key) {
          return storeInstance.delete(key)
        }
      }
    })
    starling.load()

    // when
    const texts = await starling.load()
    // then
    expect(texts).toEqual({ cache: 'false' })
  })

  test('load - 成功 - cache false', async () => {
    // given
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: { cache: 'true' }, Updated: true }
      }
    })
    const starling = new Starling({
      ...options,
      cache: false,
      store: {
        get(key) {
          return {
            cache: 'false'
          }
        },
        set(key, value) {
          return storeInstance.setItem(key, JSON.stringify(value))
        },
        del(key) {
          return storeInstance.delete(key)
        }
      }
    })
    starling.load()

    // when
    const texts = await starling.load()
    // then
    expect(texts).toEqual({ cache: 'true' })
  })

  test('load-成功-lazyUpdate多空间时本地缓存缺少一个load返回全部最新', async () => {
    // given
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: { new: 'true' }, Updated: true }
      }
    })
    const starling = new Starling({
      ...options,
      namespace: ['test1', 'test2'],
      lazyUpdate: true,
      store: {
        get(key) {
          // version 和 text 都只有一个存在
          if (key.indexOf('version') > -1 && key.indexOf('test1') > -1) {
            return 123
          }
          if (key.indexOf('text') > -1 && key.indexOf('test1') > -1) {
            return { cache: 'true' }
          }
        },
        set(key, value) {
          return storeInstance.setItem(key, JSON.stringify(value))
        },
        del(key) {
          return storeInstance.delete(key)
        }
      }
    })
    // when
    const texts = await starling.load()
    // then 全部获取最新的文案
    expect(texts).toEqual({ new: 'true' })
  })

  test('load - 成功 - plugin插件执行', async () => {
    // given
    request.mockReturnValueOnce({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT, Updated: true }
      }
    })

    const starling = new Starling({
      ...options,
      plugins: [new TestPlugin()]
    })
    const texts = await starling.load().catch(e => {
      return e.response.data
    })
    expect(texts).toEqual({ ...EN_TXT, testplugin: 'test' })
  })
})
